import{_ as a,o as l,c as t,a5 as r}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"教程 0042：三电平 NPC 逆变器","description":"","frontmatter":{"title":"教程 0042：三电平 NPC 逆变器","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0042-three-level-npc-inverter.html","status":"learning","visibility":"public","summary":"Imported from 0042-three-level-npc-inverter.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0042-three-level-npc-inverter.md","filePath":"content/power/lessons/0042-three-level-npc-inverter.md","lastUpdated":null}'),i={name:"content/power/lessons/0042-three-level-npc-inverter.md"};function o(n,e,c,h,d,p){return l(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="教程-0042-三电平-npc-逆变器" tabindex="-1">教程 0042：三电平 NPC 逆变器 <a class="header-anchor" href="#教程-0042-三电平-npc-逆变器" aria-label="Permalink to &quot;教程 0042：三电平 NPC 逆变器&quot;">​</a></h1><p>中文主讲。一个概念：三电平 NPC 逆变器用 +、0、- 三种相电平降低器件电压应力和输出谐波。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**只讲公开 NPC 拓扑和教学控制，不记录真实器件、驱动互锁或产品输出参数。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>三电平 NPC 逆变器（three-level neutral-point-clamped inverter / NPC inverter）把每相输出钳位到 <code>+Vdc/2</code>、<code>0</code> 或 <code>-Vdc/2</code>。相比两电平桥，器件承受电压降低，输出 dv/dt 和滤波压力减小。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>中大功率三相 UPS 输出级需要高效率、低谐波和较低 EMI。NPC 逆变器适合高母线电压场景，但要增加中点平衡、更多开关状态和更严格的保护时序。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>两电平像只能在楼顶和地面之间跳；三电平多了中间平台。每一步更小，输出波形更接近正弦，但你必须管理中间平台的电荷平衡。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>phase_state in {P, O, N} P -&gt; +Vdc / 2 O -&gt; 0 through neutral clamp N -&gt; -Vdc / 2 neutral_current depends on O-state selection</p><p>三电平 SVPWM 中，小矢量存在冗余状态，冗余状态产生相同 alpha/beta 电压，但对中点电流作用相反。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>对比两电平和三电平相电压阶梯。观察三电平输出电压阶跃更小、滤波后电流纹波更低，但中点电压会随冗余状态选择漂移。</p><p>产物</p><ul><li>一张两电平/三电平相电压对比图。</li><li>一张中点电压误差随冗余状态变化的曲线。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件从 <code>svpwm_three_level()</code> 生成每相 P/O/N 状态，再映射到四个开关管的互补驱动。保护重点包括上下管直通、中点过偏、母线过压、输出过流和驱动故障。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**三电平只是两电平多一个状态。 **纠正：**调制、保护和中点平衡都会复杂很多。</li><li>**误解：**中点平衡只属于 PFC。 **纠正：**NPC 逆变器同样会影响中点电流。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能画出 P/O/N 三种相电平。</li><li>能解释 NPC 为什么降低器件电压应力。</li><li>能说明冗余小矢量和中点平衡的关系。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么三电平输出滤波压力更小？</li><li>如果中点电压持续偏高，调制层可以怎样调整？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>真实 UPS 输出级中，NPC 的中点平衡由调制层、外环还是单独控制器处理？</li><li>我只记录通用结构，不记录内部时序。</li></ul><p>**下一步：**从 UPS 三相功率级扩展到储能 PCS 的并网控制。</p><p>源稿：<code>concepts/power-electronics/three-level-npc-inverter.md</code></p><p>上一节：教程 0041：Vienna PFC 与中点电压平衡下一节：教程 0043：PCS 并网跟随型 P/Q 控制</p>',31)])])}const _=a(i,[["render",o]]);export{u as __pageData,_ as default};
